from flask import Flask, request, jsonify, send_file
from pypdf import PdfReader, PdfWriter
import os
import io
import base64

app = Flask(__name__)

PDF_BASE64 = ""

@app.route("/fill-pdf", methods=["POST", "OPTIONS"])
def fill_pdf():
    # Handle CORS preflight
    if request.method == "OPTIONS":
        response = app.make_default_options_response()
        response.headers["Access-Control-Allow-Origin"] = "*"
        response.headers["Access-Control-Allow-Headers"] = "Content-Type"
        response.headers["Access-Control-Allow-Methods"] = "POST"
        return response

    try:
        data = request.get_json(force=True, silent=True)
        if not data:
            return jsonify({"error": "No JSON body received"}), 400

        field_map = data.get("fields", {})
        secret    = data.get("secret", "")

        expected_secret = os.environ.get("API_SECRET", "legendary2026")
        if secret != expected_secret:
            return jsonify({"error": "Unauthorized"}), 401

        # Decode embedded PDF
        pdf_bytes = base64.b64decode(PDF_BASE64)
        template  = io.BytesIO(pdf_bytes)

        # Fill the form fields
        reader = PdfReader(template)
        writer = PdfWriter()
        writer.append(reader)

        for i in range(len(writer.pages)):
            writer.update_page_form_field_values(writer.pages[i], field_map)

        output = io.BytesIO()
        writer.write(output)
        output.seek(0)

        response = send_file(
            output,
            mimetype="application/pdf",
            as_attachment=True,
            download_name="filled_donation_packet.pdf"
        )
        response.headers["Access-Control-Allow-Origin"] = "*"
        return response

    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok"}), 200

if __name__ == "__main__":
    port = int(os.environ.get("PORT", 8080))
    app.run(host="0.0.0.0", port=port, debug=False)
